def merge_within(pairs):
    if not pairs:
        return []

    # Merge sorted and unsorted ranges using a heapq, handling the edge case where the first range ends before the next starts
    merged = [pairs[0]]
    heap = [(-p[1], p) for p in pairs[1:]]
    heapq.heapify(heap)

    while heap and merged[-1][1] < -heap[0][0]:
        merged.append(heap[0])
        heapq.heappop(heap)

    while heap:
        current = heap[0]
        if merged and merged[-1][1] >= current[0]:
            merged[-1][1] = max(merged[-1][1], current[1])
        else:
            merged.append(current)

    return sorted(merged)
